"""sonaloop._icons — VENDORED COPY of the sonaloop-design icon module.

Do not edit by hand. Single source of truth: ../sonaloop-design (icons.data.mjs ->
scripts/gen.mjs). Refresh this vendored copy with `make icons` / scripts/sync_icons.sh.
Vendored so the PyPI package has no local-path dependency.

Source of truth: ../../icons.data.mjs

Single icon library shared with persona-website (React). Here it renders to
SVG-string markup for server-rendered HTML.

    from sonaloop_icons import icon, hifi
    icon("search")        # -> '<svg class="ic" viewBox="0 0 24 24">...</svg>'
    icon("star")          # -> '<svg class="ic star" ...>'  (extra class from data)
    hifi("persona", 64)   # -> standalone 64px display icon

Regular icons carry geometry only; stroke/size come from the host CSS rule
`svg.ic` (sonaloop ships one). Hifi icons inline their own stroke
attributes so they render without any CSS.
"""

from __future__ import annotations

__all__ = [
    "REGULAR", "HIFI", "HIFI_ANIM_CSS",
    "icon", "hifi", "hifi_anim_css", "names", "hifi_names",
]

